                # for value in feature.get('secondaryValues', []):
                #     container['feature_groups'][label][label2].add(value.get('value', None))


def convert_sets(d):
    for key, value in list(d.items()):
        if isinstance(value, dict):
            convert_sets(value)
        elif isinstance(value, set):
            d[key] = list(value)


for container, label in (
    (seals, 'SEALS'),
    (bundles, 'BUNDLES'),
    (locks, 'LOCKS'),
    (transitions, 'TRANSITIONS'),
    (terminals, 'TERMINALS'),
    (wires, 'WIRES'),
    (housings, 'HOUSINGS'),
    (covers, 'COVERS'),
    (accessories, 'ACCESSORIES'),
    (boots, 'BOOTS'),
    (splices, 'SPLICES'),
    (generic, 'GENERIC')
):
    convert_sets(container)

    print(label)
    print('-' * 40)
    print(json.dumps(container, indent=4))
    print()
    print()
    
    
